final:
module full_adder_1bit (
    input wire A,
    input wire B,
    input wire Cin,
    output wire S,
    output wire Cout
    );

assign S = A ^ B ^ Cin;
  wire temp1_(A & B) = (A & B);
  wire temp2_(Cin & (A ^ B)) = (Cin & (A ^ B));
  assign Cout = temp1_(A & B) | temp2_(Cin & (A ^ B));

endmodule
